#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if cmd.strip().startswith("pnpm test") and "test:ci" not in cmd:
        print("Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher and won't return.", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/Write on Python files, detect recursive functions and demand
verification that depth bounds exist."""
import json, re, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name")
    if tool not in ("Edit", "Write", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}
    fpath = inp.get("file_path", "")

    if not fpath.endswith(".py"):
        return 0

    try:
        with open(fpath, "r") as f:
            content = f.read()
    except Exception:
        return 0

    func_pattern = re.compile(r"^def\s+(\w+)\s*\(", re.MULTILINE)
    functions = func_pattern.findall(content)

    recursive = []
    for fname in functions:
        pattern = rf"^def\s+{re.escape(fname)}\s*\([^)]*\):(.*?)(?=^def\s|\Z)"
        match = re.search(pattern, content, re.MULTILINE | re.DOTALL)
        if match:
            body = match.group(1)
            if re.search(rf"\b{re.escape(fname)}\s*\(", body):
                recursive.append(fname)

    if recursive:
        print(f"REQUIRED FOLLOW-UP: Recursive functions detected: {', '.join(recursive)}", file=sys.stderr)
        print("Each must have explicit depth bound or guaranteed termination on large inputs (2000+ items).", file=sys.stderr)
        print("Check each now. If unbounded, rewrite iteratively. Do not stop until verified.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After editing a Python file, run ruff check and surface violations immediately."""
import json, subprocess, sys
from pathlib import Path

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") not in ("Edit", "Write"):
        return 0

    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")

    if not file_path.endswith(".py"):
        return 0

    try:
        result = subprocess.run(
            ["ruff", "check", file_path],
            capture_output=True,
            text=True,
            timeout=10,
            cwd=ev.get("cwd", ".")
        )

        if result.returncode != 0:
            print(f"REQUIRED FOLLOW-UP: ruff check found violations in {Path(file_path).name}:", file=sys.stderr)
            for line in result.stdout.splitlines()[:10]:
                print(f"  {line}", file=sys.stderr)
            print("Fix each violation immediately. Do not proceed until done.", file=sys.stderr)
            return 2
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit on an exported identifier, grep for all references."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)"
)

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [
        {"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}
    ]

    names = set()
    for e in edits:
        for s in (e.get("old_string", ""), e.get("new_string", "")):
            m = EXPORT_DEF.search(s)
            if m:
                names.add(m.group(1))

    if not names:
        return 0

    for name in names:
        try:
            r = subprocess.run(
                ["grep", "-rn", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx", name, "."],
                capture_output=True, text=True, timeout=5
            )
            hits = [l for l in r.stdout.splitlines() if l][:20]
            if hits:
                print(f"BLOCKING: export `{name}` was edited. {len(hits)} references found:", file=sys.stderr)
                for h in hits:
                    print(f"  {h}", file=sys.stderr)
                print("Fix each, then summarize. Do not stop. Do not ask.", file=sys.stderr)
                return 2
        except Exception:
            pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

